const lead = $('Get Lead').first().json[0] || $('Get Lead').first().json;
const inventory = $('Get Inventory').all().map(i => i.json);
const triggerType = $('SMS Engine Webhook').first().json.trigger_type;

const inventoryText = inventory.map(v =>
  `${v.year} ${v.make} ${v.model} ${v.trim || ''} — ${v.color || ''} — ${v.mileage_km ? v.mileage_km.toLocaleString() + ' km' : 'New'} — $${Number(v.price).toLocaleString()}`
).join('\n');

const triggerInstructions = {
  first_contact: 'This is the very first message. Introduce yourself briefly, reference their vehicle interest if provided, ask one qualifying question. Sign with your first name.',
  follow_up_day3: 'Lead has not replied in 3 days. Short, friendly check-in. One question only. Keep it under 100 characters if possible.',
  follow_up_day7: 'No reply in 7 days. Try a different angle — ask about timing or budget, not the specific vehicle.',
  follow_up_day14: 'Two weeks with no reply. This is a last real attempt. Keep it human and low-pressure.',
  follow_up_day30: 'Final follow-up. Acknowledge that some time has passed. Leave the door open for the future.',
  inbound_reply: 'The lead just replied. Respond naturally and directly to what they said. Classify intent based on their message.'
};

const systemPrompt = `You are an AI assistant for ${ $env.DEALERSHIP_NAME} in ${$env.DEALERSHIP_CITY}.
Sales contact: ${$env.SALESPERSON_NAME}, ${$env.SALESPERSON_PHONE}
Hours: ${$env.DEALERSHIP_HOURS}

CURRENT AVAILABLE INVENTORY:
${inventoryText}

RULES:
- SMS under 160 characters unless content truly requires more
- Professional but warm — not pushy, not robotic
- Never use em dashes
- No filler phrases
- Always include a clear next step or question
- Sign with salesperson first name on first contact only
- Never lie about inventory availability

OUTPUT FORMAT: JSON only.
{"sms_text": "...", "intent_score": "hot|warm|cold", "intent_reasoning": "1 sentence"}

INTENT DEFINITIONS:
hot: asking for price/availability, wants test drive, ready to buy
warm: engaged, comparing options, needs nurturing
cold: no reply yet, vague interest, or generic inquiry`;

const userMessage = `LEAD CONTEXT:
Name: ${lead.first_name} ${lead.last_name}
Source: ${lead.source}
Vehicle interest: ${lead.vehicle_interest || '(not specified)'}
Trigger: ${triggerType}
Sequence step: ${lead.sequence_step}

TRIGGER INSTRUCTIONS: ${triggerInstructions[triggerType] || triggerInstructions.first_contact}`;

return [{
  json: {
    lead,
    triggerType,
    systemPrompt,
    userMessage
  }
}];

const lead = $('Build Claude Prompt').first().json.lead;
const rawText = $json.content[0].text.trim();

let parsed;
try {
  parsed = JSON.parse(rawText);
} catch (e) {
  // Fallback if Claude returns invalid JSON
  parsed = {
    sms_text: `Hi ${lead.first_name}, thanks for your interest! I'd love to help you find the right vehicle. What's most important to you — price, mileage, or features? — ${$env.SALESPERSON_NAME}`,
    intent_score: 'cold',
    intent_reasoning: 'Fallback: Claude response could not be parsed'
  };
}

const demoMode = lead.demo_mode === true;
const smsText = demoMode ? `[DEMO] ${parsed.sms_text}` : parsed.sms_text;

return {
  json: {
    lead,
    sms_text: smsText,
    intent_score: parsed.intent_score,
    intent_reasoning: parsed.intent_reasoning,
    demo_mode: demoMode
  }
};

const lead = $('Parse Claude Response').first().json.lead;
const intentScore = $('Parse Claude Response').first().json.intent_score;
const triggerType = $('Build Claude Prompt').first().json.triggerType;

// Days until next follow-up per sequence step
const followUpDays = { 0: 3, 1: 4, 2: 7, 3: 16, 4: null };
const nextStep = (lead.sequence_step || 0) + 1;
const daysUntilNext = followUpDays[lead.sequence_step || 0];

let nextFollowUp = null;
if (daysUntilNext !== null && intentScore !== 'hot') {
  const d = new Date();
  d.setDate(d.getDate() + daysUntilNext);
  nextFollowUp = d.toISOString();
}

// Map intent score to stage
const stageMap = { hot: 'hot', warm: 'warm', cold: lead.stage === 'new' ? 'contacted' : lead.stage };
const newStage = stageMap[intentScore] || lead.stage;

return {
  json: {
    lead_id: lead.id,
    intent_score: intentScore,
    stage: newStage,
    sequence_step: nextStep,
    sms_count: (lead.sms_count || 0) + 1,
    last_sms_at: new Date().toISOString(),
    next_follow_up: nextFollowUp
  }
};
